-- PostgreSQL demo initialization for Cindy Beauty backend on Render.
-- Safe to run multiple times: no DROP/TRUNCATE, tables use IF NOT EXISTS,
-- seed rows use fixed IDs with ON CONFLICT.

BEGIN;

CREATE TABLE IF NOT EXISTS "Admins" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "FullName" text NOT NULL,
    "Email" text NOT NULL,
    "Password" text NOT NULL,
    "Role" text NOT NULL
);

CREATE TABLE IF NOT EXISTS "AdminMessages" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "SenderName" varchar(100) NOT NULL,
    "SenderEmail" varchar(100),
    "SenderPhone" varchar(20),
    "ProductId" integer,
    "ProductName" varchar(200),
    "Content" varchar(1000) NOT NULL,
    "AdminReply" text,
    "IsRead" boolean NOT NULL DEFAULT false,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    "RepliedAt" timestamp without time zone
);

CREATE TABLE IF NOT EXISTS "AdminNotificationReads" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Type" text NOT NULL,
    "TargetId" integer NOT NULL,
    "ReadAt" timestamp without time zone NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "Banners" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Title" text NOT NULL,
    "Description" text,
    "ImageUrl" text NOT NULL,
    "LinkUrl" text,
    "IsActive" boolean NOT NULL DEFAULT true,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "Brands" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Name" varchar(100) NOT NULL,
    "Description" varchar(1000),
    "LogoUrl" text,
    "BannerUrl" text,
    "ThumbnailUrl" text,
    "Country" text,
    "Website" text,
    "FoundedYear" integer,
    "IsActive" boolean NOT NULL DEFAULT true,
    "IsFeatured" boolean NOT NULL DEFAULT false,
    "Slug" text,
    "MetaTitle" text,
    "MetaDescription" text,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    "UpdatedAt" timestamp without time zone
);

CREATE TABLE IF NOT EXISTS "Categories" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Name" varchar(100) NOT NULL,
    "Icon" text NOT NULL,
    "Description" text,
    "IsActive" boolean NOT NULL DEFAULT true,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "Customers" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "FullName" text NOT NULL,
    "Email" text NOT NULL,
    "Phone" text NOT NULL,
    "Password" text NOT NULL,
    "IsBlocked" boolean NOT NULL DEFAULT false
);

CREATE TABLE IF NOT EXISTS "Employees" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "FullName" text NOT NULL,
    "Email" text NOT NULL,
    "Password" text NOT NULL,
    "Phone" text NOT NULL,
    "Role" text NOT NULL,
    "IsActive" boolean NOT NULL DEFAULT true,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "Users" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "FullName" text NOT NULL,
    "Phone" text NOT NULL,
    "Email" text NOT NULL,
    "Password" text NOT NULL,
    "Gender" text NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    "OtpCode" text,
    "OtpExpired" timestamp without time zone
);

CREATE TABLE IF NOT EXISTS "Promotions" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Title" text NOT NULL,
    "Description" text NOT NULL,
    "DiscountPercent" integer NOT NULL,
    "BannerUrl" text NOT NULL
);

CREATE TABLE IF NOT EXISTS "Products" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Name" varchar(200) NOT NULL,
    "Description" text NOT NULL,
    "Origin" text NOT NULL,
    "Price" numeric(18,2) NOT NULL,
    "Stock" integer NOT NULL,
    "ImageUrl" text NOT NULL,
    "Rating" double precision NOT NULL,
    "CategoryId" integer NOT NULL,
    "BrandId" integer,
    "SkinType" text,
    "Concern" text,
    "PriceRange" text,
    "DiscountPercent" integer NOT NULL,
    "Status" text NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    CONSTRAINT "FK_Products_Categories_CategoryId"
        FOREIGN KEY ("CategoryId") REFERENCES "Categories"("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Products_Brands_BrandId"
        FOREIGN KEY ("BrandId") REFERENCES "Brands"("Id") ON DELETE RESTRICT
);

CREATE TABLE IF NOT EXISTS "PromotionProducts" (
    "PromotionId" integer NOT NULL,
    "ProductId" integer NOT NULL,
    CONSTRAINT "PK_PromotionProducts" PRIMARY KEY ("PromotionId", "ProductId"),
    CONSTRAINT "FK_PromotionProducts_Promotions_PromotionId"
        FOREIGN KEY ("PromotionId") REFERENCES "Promotions"("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_PromotionProducts_Products_ProductId"
        FOREIGN KEY ("ProductId") REFERENCES "Products"("Id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS "Reviews" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "ProductId" integer NOT NULL,
    "UserName" varchar(100) NOT NULL,
    "UserEmail" varchar(100),
    "Comment" varchar(2000) NOT NULL,
    "Rating" integer NOT NULL,
    "MediaUrl" text,
    "MediaType" text,
    "IsHidden" boolean NOT NULL DEFAULT false,
    "AdminReply" text,
    "IsSpam" boolean NOT NULL DEFAULT false,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    "UpdatedAt" timestamp without time zone,
    CONSTRAINT "FK_Reviews_Products_ProductId"
        FOREIGN KEY ("ProductId") REFERENCES "Products"("Id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS "InventoryLogs" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "ProductId" integer NOT NULL,
    "Type" text NOT NULL,
    "Quantity" integer NOT NULL,
    "Note" text,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    CONSTRAINT "FK_InventoryLogs_Products_ProductId"
        FOREIGN KEY ("ProductId") REFERENCES "Products"("Id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS "Orders" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "CustomerName" varchar(100) NOT NULL,
    "Phone" varchar(20) NOT NULL,
    "Address" varchar(300) NOT NULL,
    "Email" varchar(200),
    "TotalAmount" numeric(18,2) NOT NULL,
    "Status" text NOT NULL,
    "PaymentMethod" text NOT NULL,
    "PaymentStatus" text NOT NULL,
    "ShippingFee" numeric NOT NULL DEFAULT 0,
    "ShippingCode" text,
    "Note" text,
    "CustomerId" integer,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    "UpdatedAt" timestamp without time zone,
    "CompletedAt" timestamp without time zone,
    CONSTRAINT "FK_Orders_Customers_CustomerId"
        FOREIGN KEY ("CustomerId") REFERENCES "Customers"("Id") ON DELETE SET NULL
);

CREATE TABLE IF NOT EXISTS "OrderDetails" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "OrderId" integer NOT NULL,
    "ProductId" integer NOT NULL,
    "Quantity" integer NOT NULL,
    "Price" numeric(18,2) NOT NULL,
    CONSTRAINT "FK_OrderDetails_Orders_OrderId"
        FOREIGN KEY ("OrderId") REFERENCES "Orders"("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_OrderDetails_Products_ProductId"
        FOREIGN KEY ("ProductId") REFERENCES "Products"("Id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS "Conversations" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "CustomerName" varchar(100) NOT NULL,
    "CustomerEmail" varchar(100),
    "CustomerPhone" varchar(20),
    "ProductId" integer,
    "ProductName" varchar(200),
    "IsClosed" boolean NOT NULL DEFAULT false,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    "UpdatedAt" timestamp without time zone NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "ConversationMessages" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "ConversationId" integer NOT NULL,
    "SenderType" varchar(20) NOT NULL,
    "Content" varchar(1000) NOT NULL,
    "IsRead" boolean NOT NULL DEFAULT false,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW(),
    CONSTRAINT "FK_ConversationMessages_Conversations_ConversationId"
        FOREIGN KEY ("ConversationId") REFERENCES "Conversations"("Id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS "CustomerNotifications" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "CustomerEmail" text,
    "CustomerPhone" text,
    "Title" text NOT NULL,
    "Content" text NOT NULL,
    "Type" text NOT NULL,
    "Link" text,
    "IsRead" boolean NOT NULL DEFAULT false,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "Attendances" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "EmployeeId" integer NOT NULL,
    "CheckInTime" timestamp without time zone NOT NULL DEFAULT NOW(),
    "CheckOutTime" timestamp without time zone,
    "Status" text NOT NULL,
    "Note" text,
    CONSTRAINT "FK_Attendances_Employees_EmployeeId"
        FOREIGN KEY ("EmployeeId") REFERENCES "Employees"("Id") ON DELETE CASCADE
);

CREATE INDEX IF NOT EXISTS "IX_Attendances_EmployeeId" ON "Attendances" ("EmployeeId");
CREATE INDEX IF NOT EXISTS "IX_ConversationMessages_ConversationId" ON "ConversationMessages" ("ConversationId");
CREATE INDEX IF NOT EXISTS "IX_InventoryLogs_ProductId" ON "InventoryLogs" ("ProductId");
CREATE INDEX IF NOT EXISTS "IX_OrderDetails_OrderId" ON "OrderDetails" ("OrderId");
CREATE INDEX IF NOT EXISTS "IX_OrderDetails_ProductId" ON "OrderDetails" ("ProductId");
CREATE INDEX IF NOT EXISTS "IX_Orders_CustomerId" ON "Orders" ("CustomerId");
CREATE INDEX IF NOT EXISTS "IX_Products_BrandId" ON "Products" ("BrandId");
CREATE INDEX IF NOT EXISTS "IX_Products_CategoryId" ON "Products" ("CategoryId");
CREATE INDEX IF NOT EXISTS "IX_PromotionProducts_ProductId" ON "PromotionProducts" ("ProductId");
CREATE INDEX IF NOT EXISTS "IX_Reviews_ProductId" ON "Reviews" ("ProductId");

